// Simulating gravity vector mechanics
const G = 0.0001; // Gravitational constant
function updateOrbit(body, parent) {
  const dx = parent.position.x - body.position.x;
  const dy = parent.position.y - body.position.y;
  const dz = parent.position.z - body.position.z;
  const r2 = dx*dx + dy*dy + dz*dz;
  const r = Math.sqrt(r2);

  // Gravitational force magnitude
  const force = (G * body.mass * parent.mass) / r2;

  // Acceleration vector components
  body.velocity.x += (force * dx) / (body.mass * r);
  body.velocity.y += (force * dy) / (body.mass * r);
  body.velocity.z += (force * dz) / (body.mass * r);

  // Apply velocity to position
  body.position.add(body.velocity);
}

