// Mutative Vector Arithmetic for Canvas Performance
class Vector2D {
  constructor(x = 0, y = 0) {
    this.x = x;
    this.y = y;
  }

  add(v) {
    this.x += v.x;
    this.y += v.y;
    return this;
  }

  sub(v) {
    this.x -= v.x;
    this.y -= v.y;
    return this;
  }

  mult(scalar) {
    this.x *= scalar;
    this.y *= scalar;
    return this;
  }

  magnitude() {
    return Math.sqrt(this.x * this.x + this.y * this.y);
  }
}

// React 19 useActionState form handling
import { useActionState } from 'react';

async function updateProfile(prevState, formData) {
  try {
    const name = formData.get("username");
    await saveProfileToDatabase(name);
    return { success: true, message: "Profile updated!" };
  } catch (error) {
    return { success: false, message: error.message };
  }
}

function ProfileForm() {
  const [state, formAction, isPending] = useActionState(updateProfile, null);

  return (
    <form action={formAction}>
      <input name="username" type="text" disabled={isPending} />
      <button type="submit" disabled={isPending}>
        {isPending ? 'Saving...' : 'Save'}
      </button>
      {state && <p className="feedback">{state.message}</p>}
    </form>
  );
}
